onClick:
{{
  (async () => {
    // 1. Kiểm tra điều kiện đầu vào
    if (!inp_MaCongCu.text || !inp_SoLuong.text || !sel_NhanVien.selectedOptionValue) {
      return showAlert('⚠️ Vui lòng điền đầy đủ: Mã vật liệu, Số lượng và Nhân viên!', 'warning');
    }

    try {
      // 2. Thực thi lệnh Nhập kho
      await Action_NhapKho.run();

      // 3. Làm mới TẤT CẢ các bảng liên quan đồng bộ
      // Dùng Promise.all giúp tải dữ liệu nhanh hơn so với việc đợi từng bảng
      await Promise.all([
        Get_Bang_Tool.run(),      // Load lại bảng danh mục công cụ
        Get_LS_Nhap.run(),        // Load lại lịch sử nhập
        Get_Inventory_Data.run()  // Load lại bảng kiểm kê ngay lập tức
      ]);

      // 4. Reset Form và báo thành công
      resetWidget('Form_Xuat_Nhap_1', true);
      showAlert('✅ Nhập kho thành công! / 入库成功!', 'success');

    } catch (err) {
      // 5. Xử lý lỗi nếu có
      console.error("Lỗi khi nhập kho:", err);
      showAlert('❌ Lỗi: ' + err.message, 'error');
    }
  })()
}}
